{
  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using clues from the Foundations of The Importance of Play in Learning. Use the terms related to cognitive development and problem-solving skills.",
        "codeTemplate": "Play enhances __________ and __________, allowing youth to explore new ideas and concepts.",
        "options": [
          "creativity",
          "imagination",
          "problem-solving",
          "communication"
        ],
        "correctAnswer": "creativity,imagination",
        "explanation": "According to the Foundations of The Importance of Play in Learning, play enhances creativity and imagination, which are essential for cognitive development."
      },
      {
        "instruction": "Complete the statement using concepts from the earlier lessons on play's role in learning.",
        "codeTemplate": "Engaging in play helps develop __________ skills through __________.",
        "options": [
          "problem-solving",
          "social",
          "motor",
          "communication"
        ],
        "correctAnswer": "problem-solving,play",
        "explanation": "Engaging in play helps develop problem-solving skills through play, as highlighted in the module."
      }
    ]
  }
}
